DIR="/Users/jnsilva/Claude/jnsilva-site/public/images/places"
mkdir -p "$DIR"
cd "$DIR"

dl() {
  local fname="$1" uuid="$2" crop="$3" exp="$4" hmac="$5" sub="${6:-1/1}"
